from collections import defaultdict


class PerUserBudgetRegistry:
    def __init__(self, limit_usd: float, window_seconds: int = 86_400):
        self._lock = threading.Lock()
        self._budgets: dict[str, BudgetEnforcer] = {}
        self._limit = limit_usd
        self._window = window_seconds

    def get(self, user_id: str) -> BudgetEnforcer:
        with self._lock:
            if user_id not in self._budgets:
                self._budgets[user_id] = BudgetEnforcer(
                    limit_usd=self._limit,
                    window_seconds=self._window,
                )
            return self._budgets[user_id]

    def enforce(self, user_id: str, cost_usd: float):
        self.get(user_id).check_and_record(cost_usd)

    def report(self) -> list[dict]:
        with self._lock:
            rows = []
            for uid, b in self._budgets.items():
                rows.append({
                    "user_id": uid,
                    "remaining_usd": b.remaining_usd,
                    "spent_usd": b.limit - b.remaining_usd,
                })
        return sorted(rows, key=lambda r: r["spent_usd"], reverse=True)


